8503 std::optional<std::pair<CmpPredicate, Constant *>>
8504 llvm::getFlippedStrictnessPredicateAndConstant(CmpPredicate Pred, Constant *C) {
8505   assert(ICmpInst::isRelational(Pred) && ICmpInst::isIntPredicate(Pred) &&
8506          "Only for relational integer predicates.");
8507   if (isa<UndefValue>(C))
8508     return std::nullopt;
8509 
8510   Type *Type = C->getType();
8511   bool IsSigned = ICmpInst::isSigned(Pred);
8512 
8513   CmpInst::Predicate UnsignedPred = ICmpInst::getUnsignedPredicate(Pred);
8514   bool WillIncrement =
8515       UnsignedPred == ICmpInst::ICMP_ULE || UnsignedPred == ICmpInst::ICMP_UGT;
8516 
8517   // Check if the constant operand can be safely incremented/decremented
8518   // without overflowing/underflowing.
8519   auto ConstantIsOk = [WillIncrement, IsSigned](ConstantInt *C) {
8520     return WillIncrement ? !C->isMaxValue(IsSigned) : !C->isMinValue(IsSigned);
8521   };
8522 
8523   Constant *SafeReplacementConstant = nullptr;
8524   if (auto *CI = dyn_cast<ConstantInt>(C)) {
8525     // Bail out if the constant can't be safely incremented/decremented.
8526     if (!ConstantIsOk(CI))
8527       return std::nullopt;
8528   } else if (auto *FVTy = dyn_cast<FixedVectorType>(Type)) {
8529     unsigned NumElts = FVTy->getNumElements();
8530     for (unsigned i = 0; i != NumElts; ++i) {
8531       Constant *Elt = C->getAggregateElement(i);
8532       if (!Elt)
8533         return std::nullopt;
8534 
8535       if (isa<UndefValue>(Elt))
8536         continue;
8537 
8538       // Bail out if we can't determine if this constant is min/max or if we
8539       // know that this constant is min/max.
8540       auto *CI = dyn_cast<ConstantInt>(Elt);
8541       if (!CI || !ConstantIsOk(CI))
8542         return std::nullopt;
8543 
8544       if (!SafeReplacementConstant)
8545         SafeReplacementConstant = CI;
8546     }
8547   } else if (isa<VectorType>(C->getType())) {
8548     // Handle scalable splat
8549     Value *SplatC = C->getSplatValue();
8550     auto *CI = dyn_cast_or_null<ConstantInt>(SplatC);
8551     // Bail out if the constant can't be safely incremented/decremented.
8552     if (!CI || !ConstantIsOk(CI))
8553       return std::nullopt;
8554   } else {
8555     // ConstantExpr?
8556     return std::nullopt;
8557   }
8558 
8559   // It may not be safe to change a compare predicate in the presence of
8560   // undefined elements, so replace those elements with the first safe constant
8561   // that we found.
8562   // TODO: in case of poison, it is safe; let's replace undefs only.
8563   if (C->containsUndefOrPoisonElement()) {
8564     assert(SafeReplacementConstant && "Replacement constant not set");
8565     C = Constant::replaceUndefsWith(C, SafeReplacementConstant);
8566   }
8567 
8568   CmpInst::Predicate NewPred = CmpInst::getFlippedStrictnessPredicate(Pred);
8569 
8570   // Increment or decrement the constant.
8571   Constant *OneOrNegOne = ConstantInt::get(Type, WillIncrement ? 1 : -1, true);
8572   Constant *NewC = ConstantExpr::getAdd(C, OneOrNegOne);
8573 
8574   return std::make_pair(NewPred, NewC);
8575 }
